import{_ as t,o as l,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"F15: 關係人交易與利益輸送風險 - 財務審計專家 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/3105_穩懋/20260503/F15_關係人交易與利益輸送風險.md","filePath":"審計報告庫/財務審計/3105_穩懋/20260503/F15_關係人交易與利益輸送風險.md"}'),e={name:"審計報告庫/財務審計/3105_穩懋/20260503/F15_關係人交易與利益輸送風險.md"};function i(n,a,s,h,_,d){return l(),r("div",null,[...a[0]||(a[0]=[o('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h1 id="f15-關係人交易與利益輸送風險-財務審計專家-審計報告" tabindex="-1">F15: 關係人交易與利益輸送風險 - 財務審計專家 審計報告 <a class="header-anchor" href="#f15-關係人交易與利益輸送風險-財務審計專家-審計報告" aria-label="Permalink to &quot;F15: 關係人交易與利益輸送風險 - 財務審計專家 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>是否存在異常大額的關係人交易？定價是否符合市場行情？是否存在利益輸送或虛增利潤之嫌？</p></blockquote><h2 id="🎯-專家直斷-50-字" tabindex="-1">🎯 專家直斷（50 字） <a class="header-anchor" href="#🎯-專家直斷-50-字" aria-label="Permalink to &quot;🎯 專家直斷（50 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：外部關係人交易極少（進貨僅 $31K）無利益輸送。農牧子公司背書保證 $8.33B 形成風險敞口但現金流可支撐。</li><li><strong>風險評級</strong>：低</li><li><strong>數據時效</strong>：根據截至 2025 年最新公開數據</li></ul><h2 id="📊-診斷評級-138-字" tabindex="-1">📊 診斷評級（138 字） <a class="header-anchor" href="#📊-診斷評級-138-字" aria-label="Permalink to &quot;📊 診斷評級（138 字）&quot;">​</a></h2><ul><li><strong>重點數據</strong>：外部關係人進貨僅 $31K（&lt;0.01%），無異常。背書保證對子公司 $8.33B（佔淨值 20%），資金貸與農牧子公司 $1.1B。</li><li><strong>診斷見解</strong>：外部關係人交易規模極微無利益輸送。集團資金集中流向虧損農牧子公司，背書保證敞口 20% 為主要風險，惟本業現金流尚可支撐。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="交易規模與公平性" tabindex="-1">交易規模與公平性 <a class="header-anchor" href="#交易規模與公平性" aria-label="Permalink to &quot;交易規模與公平性&quot;">​</a></h3><ul><li><strong>核心重點</strong>：外部關係人交易僅有關聯企業進貨 NT$31K（年報載明價格與條件與一般廠商無顯著不同）。佔營收與成本比重均小於 0.01%，無需啟動 5-10% 的警戒標準。母子公司內部交易雖金額較大（銷貨 NT$161M），但均已於合併報表沖銷，不影響合併淨利。</li><li><strong>深度見解</strong>：關係人交易的透明度良好，年報附註完整揭露。未發現異常定價或帳期偏離。向主要管理人員借款 NT$295M 利率 2% 屬合理範圍。</li></ul><h3 id="資金貸與與背書保證" tabindex="-1">資金貸與與背書保證 <a class="header-anchor" href="#資金貸與與背書保證" aria-label="Permalink to &quot;資金貸與與背書保證&quot;">​</a></h3><ul><li><strong>核心重點</strong>：資金貸與集中於農牧子公司（江蘇全穩康源 NT$631M、穩盈 NT$120M），均為短期資金調度，利率 1%。母公司對子公司背書保證餘額 NT$8.33B，農牧部門佔比最高（江蘇穩盈 NT$3.46B）。農牧部門 2025 年虧損 NT$1.17B，已連續多年虧損。</li><li><strong>深度見解</strong>：穩懋持續以資金貸與與背書保證支持虧損農牧子公司，形成「類紓困」的現金流出。若農牧部門無法轉虧為盈，母公司面臨潛在代償風險。</li></ul><h2 id="💡-專家評析-≥2-個利空關鍵字" tabindex="-1">💡 專家評析（≥2 個利空關鍵字） <a class="header-anchor" href="#💡-專家評析-≥2-個利空關鍵字" aria-label="Permalink to &quot;💡 專家評析（≥2 個利空關鍵字）&quot;">​</a></h2><ol><li><p><strong>農牧子公司持續虧損，集團資源持續失血</strong>：農牧部門虧損 NT$1.17B，且資金貸與 NT$1.1B、背書保證 NT$8.33B，顯示管理層對非核心業務的資源配置不合理。若該部門無法改善，繼續输血將稀釋本業獲利。</p></li><li><p><strong>對子公司背書保證達淨值 20%，隱含風險不可忽視</strong>：NT$8.33B 的背書保證若發生違約，將直接衝擊母公司現金部位。農牧子公司資產負債狀況未單獨揭露，透明度不足，構成潛在的隱含負債風險。</p></li><li><p><strong>關係人應收款項集中於虧損子公司</strong>：應收款項 NT$1.03B 主要來自農牧子公司，若其無法清償，母公司需提列減損損失。2025 年已認列 NT$1.64B 減損（可能含農牧），需持續關注。</p></li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>年報 PDF：2025_Q4_3105_合併.pdf（關係人交易 p.74-75、資金貸與與背書保證附表 p.80-84）</li><li>關鍵核對碼：外部關係人進貨 NT$31K, 背書保證 NT$8.33B(佔淨值20%), 農牧虧損 NT$1.17B</li></ul>',17)])])}const $=t(e,[["render",i]]);export{c as __pageData,$ as default};
